import { useState, useEffect, useRef } from 'react'
import { useLocation, useNavigate } from 'react-router-dom'
import { Box, Typography, Avatar } from '@mui/material'
import { motion, AnimatePresence } from 'framer-motion'
import { useAuthStore } from '../../store/authStore'
import { useThemeMode } from '../../context/ThemeContext'
import { useLatestSensorData } from '../../hooks/useSensorData'
import { alertsApi } from '../../services/api'

const NAV_ITEMS = [
  { label: 'Dashboard',   path: '/dashboard' },
  { label: 'Historique',  path: '/history'   },
  { label: 'Ext.',        path: '/external'  },
  { label: 'Ventilateurs',path: '/devices'   },
  { label: 'Alertes',     path: '/alerts'    },
  { label: 'Vue 3D',      path: '/3d'        },
]

function Clock() {
  const [now, setNow] = useState(new Date())
  useEffect(() => {
    const t = setInterval(() => setNow(new Date()), 1000)
    return () => clearInterval(t)
  }, [])
  return (
    <Typography sx={{ fontFamily: '"JetBrains Mono", monospace', fontSize: '0.68rem', opacity: 0.55, whiteSpace: 'nowrap', letterSpacing: '0.04em' }}>
      {now.toLocaleDateString('fr-FR', { weekday: 'short', day: '2-digit', month: 'short' })}
      {' · '}
      {now.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
    </Typography>
  )
}

export default function NavBar() {
  const location = useLocation()
  const navigate  = useNavigate()
  const { username, role, logout } = useAuthStore()
  const { mode, toggle } = useThemeMode()
  const dark = mode === 'dark'
  const { lastUpdate } = useLatestSensorData(60000)
  const [alertCount, setAlertCount] = useState(0)
  const navRef = useRef<HTMLDivElement>(null)
  const [indicatorStyle, setIndicatorStyle] = useState({ left: 0, width: 0 })

  useEffect(() => {
    alertsApi.list().then((r) => {
      setAlertCount(r.data.filter((a: any) => !a.acknowledged).length)
    }).catch(() => {})
    const t = setInterval(() => {
      alertsApi.list().then((r) => setAlertCount(r.data.filter((a: any) => !a.acknowledged).length)).catch(() => {})
    }, 30000)
    return () => clearInterval(t)
  }, [])

  useEffect(() => {
    if (!navRef.current) return
    const activeEl = navRef.current.querySelector('[data-active="true"]') as HTMLElement
    if (activeEl) {
      const navRect = navRef.current.getBoundingClientRect()
      const elRect = activeEl.getBoundingClientRect()
      setIndicatorStyle({ left: elRect.left - navRect.left, width: elRect.width })
    }
  }, [location.pathname])

  const isLive = lastUpdate ? (Date.now() - lastUpdate.getTime()) < 90000 : false

  const primary  = dark ? '#00aaff' : '#0070d4'
  const textPri  = dark ? '#e2ecf8' : '#1a2540'
  const textSec  = dark ? '#8aaccc' : '#5a7090'
  const navBg    = dark ? 'rgba(6,10,22,0.97)'  : 'rgba(255,255,255,0.98)'
  const border   = dark ? 'rgba(0,170,255,0.1)' : 'rgba(0,80,160,0.1)'

  return (
    <Box
      component="nav"
      sx={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1200,
        height: 56,
        background: navBg,
        backdropFilter: 'blur(24px)',
        WebkitBackdropFilter: 'blur(24px)',
        borderBottom: `1px solid ${border}`,
        display: 'flex', alignItems: 'center',
        px: { xs: 2, md: 3 },
        gap: 0,
      }}
    >
      {/* Logo */}
      <Box
        onClick={() => navigate('/dashboard')}
        sx={{ display: 'flex', alignItems: 'center', gap: 1.2, cursor: 'pointer', mr: 4, flexShrink: 0, userSelect: 'none' }}
      >
        <Box sx={{
          width: 26, height: 26, borderRadius: '7px',
          background: dark
            ? 'linear-gradient(135deg, #0066bb 0%, #00ddaa 100%)'
            : 'linear-gradient(135deg, #0060c0 0%, #00b898 100%)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: '12px', boxShadow: `0 2px 10px ${primary}44`, flexShrink: 0,
        }}>🌿</Box>
        <Box sx={{ display: { xs: 'none', sm: 'block' } }}>
          <Typography sx={{ fontWeight: 700, fontSize: '0.85rem', color: textPri, lineHeight: 1.1, letterSpacing: '-0.01em' }}>
            Serre Fraisier
          </Typography>
          <Typography sx={{ fontSize: '0.57rem', color: textSec, fontFamily: '"JetBrains Mono", monospace', lineHeight: 1, opacity: 0.7 }}>
            Supervision climatique
          </Typography>
        </Box>
      </Box>

      {/* Nav links with sliding indicator */}
      <Box
        ref={navRef}
        sx={{ display: { xs: 'none', md: 'flex' }, alignItems: 'center', gap: 0, flex: 1, position: 'relative' }}
      >
        {/* Animated sliding background indicator */}
        <motion.div
          animate={{ left: indicatorStyle.left, width: indicatorStyle.width }}
          transition={{ type: 'spring', stiffness: 400, damping: 36 }}
          style={{
            position: 'absolute',
            bottom: -16,
            height: 2,
            borderRadius: 4,
            background: `linear-gradient(90deg, transparent, ${primary}, transparent)`,
            pointerEvents: 'none',
          }}
        />

        {NAV_ITEMS.map((item) => {
          const active = location.pathname === item.path
          const isAlerts = item.path === '/alerts'
          return (
            <Box
              key={item.path}
              data-active={active ? 'true' : 'false'}
              onClick={() => navigate(item.path)}
              sx={{
                position: 'relative',
                px: 1.6, py: 1,
                cursor: 'pointer',
                borderRadius: '8px',
                transition: 'background 0.18s, color 0.18s',
                userSelect: 'none',
                background: active
                  ? (dark ? 'rgba(0,170,255,0.09)' : 'rgba(0,112,212,0.07)')
                  : 'transparent',
                '&:hover': {
                  background: dark ? 'rgba(0,170,255,0.06)' : 'rgba(0,112,212,0.05)',
                },
              }}
            >
              <Typography sx={{
                fontSize: '0.8rem',
                fontWeight: active ? 700 : 400,
                color: active ? primary : textSec,
                transition: 'color 0.18s, font-weight 0.18s',
                whiteSpace: 'nowrap',
                letterSpacing: active ? '0' : '0.01em',
                display: 'flex', alignItems: 'center', gap: 0.5,
              }}>
                {item.label}
                {isAlerts && alertCount > 0 && (
                  <Box component="span" sx={{
                    display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                    width: 16, height: 16, borderRadius: '50%',
                    bgcolor: '#e8334a', color: '#fff', fontSize: '0.58rem', fontWeight: 700,
                    lineHeight: 1,
                  }}>
                    {alertCount > 9 ? '9+' : alertCount}
                  </Box>
                )}
              </Typography>
            </Box>
          )
        })}
      </Box>

      {/* Mobile spacer */}
      <Box sx={{ flex: 1, display: { md: 'none' } }} />

      {/* Right controls */}
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, flexShrink: 0 }}>

        {/* Live dot */}
        <Box sx={{ display: { xs: 'none', lg: 'flex' }, alignItems: 'center', gap: 0.7 }}>
          <Box sx={{
            width: 6, height: 6, borderRadius: '50%', flexShrink: 0,
            bgcolor: isLive ? (dark ? '#00e87a' : '#10b981') : '#f59e0b',
            boxShadow: isLive ? `0 0 8px ${dark ? '#00e87a' : '#10b981'}` : 'none',
            animation: isLive ? 'navPulse 2s infinite' : 'none',
            '@keyframes navPulse': { '0%,100%': { opacity: 1 }, '50%': { opacity: 0.45 } },
          }} />
          <Typography sx={{ fontSize: '0.65rem', color: textSec, fontFamily: '"JetBrains Mono", monospace', letterSpacing: '0.04em' }}>
            {isLive ? 'EN DIRECT' : 'Hors ligne'}
          </Typography>
        </Box>

        {/* Clock */}
        <Box sx={{ display: { xs: 'none', xl: 'block' } }}>
          <Clock />
        </Box>

        {/* Dark / Light toggle */}
        <Box
          onClick={toggle}
          sx={{
            display: 'flex', alignItems: 'center', gap: 0.6,
            px: 1.2, py: 0.5, borderRadius: '20px', cursor: 'pointer', userSelect: 'none',
            border: `1px solid ${border}`,
            background: dark ? 'rgba(0,170,255,0.07)' : 'rgba(0,80,160,0.05)',
            transition: 'all 0.2s',
            '&:hover': { borderColor: primary, background: dark ? 'rgba(0,170,255,0.13)' : 'rgba(0,80,160,0.1)' },
          }}
        >
          <Typography sx={{ fontSize: '0.7rem', fontWeight: 600, color: primary, fontFamily: '"JetBrains Mono", monospace', whiteSpace: 'nowrap' }}>
            {dark ? '☀ Clair' : '◑ Sombre'}
          </Typography>
        </Box>

        {/* Role badge */}
        <Box sx={{
          px: 0.9, py: 0.3, borderRadius: '6px',
          bgcolor: role === 'admin'
            ? (dark ? 'rgba(0,170,255,0.1)' : 'rgba(0,112,212,0.08)')
            : (dark ? 'rgba(0,232,122,0.1)' : 'rgba(16,185,129,0.08)'),
          border: `1px solid ${role === 'admin' ? primary + '33' : (dark ? '#00e87a33' : '#10b98133')}`,
          display: { xs: 'none', sm: 'flex' }, alignItems: 'center',
        }}>
          <Typography sx={{ fontSize: '0.62rem', fontWeight: 700, color: role === 'admin' ? primary : (dark ? '#00e87a' : '#10b981'), fontFamily: '"JetBrains Mono", monospace', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
            {role === 'admin' ? 'Admin' : 'Viewer'}
          </Typography>
        </Box>

        {/* User avatar + name */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.7 }}>
          <Avatar sx={{
            width: 24, height: 24, fontSize: '0.65rem', fontWeight: 700,
            bgcolor: dark ? 'rgba(0,170,255,0.18)' : 'rgba(0,112,212,0.12)',
            color: primary, border: `1px solid ${primary}33`,
          }}>
            {username?.charAt(0).toUpperCase()}
          </Avatar>
          <Typography sx={{ fontSize: '0.78rem', fontWeight: 500, color: textPri, display: { xs: 'none', sm: 'block' } }}>
            {username}
          </Typography>
        </Box>

        {/* Logout */}
        <Box
          onClick={() => { logout(); navigate('/login') }}
          sx={{
            px: 1.2, py: 0.4, borderRadius: '8px', cursor: 'pointer', userSelect: 'none',
            border: `1px solid ${border}`, fontSize: '0.72rem', fontWeight: 500, color: textSec,
            transition: 'all 0.18s', fontFamily: '"Inter", sans-serif',
            '&:hover': { color: '#e8334a', borderColor: 'rgba(232,51,74,0.4)', background: 'rgba(232,51,74,0.05)' },
          }}
        >
          Quitter
        </Box>
      </Box>
    </Box>
  )
}

import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Box, TextField, Button, Typography, Alert, CircularProgress } from '@mui/material'
import { motion } from 'framer-motion'
import { authApi } from '../services/api'
import { useAuthStore } from '../store/authStore'
import { useThemeMode } from '../context/ThemeContext'

export default function LoginPage() {
  const navigate = useNavigate()
  const { login } = useAuthStore()
  const { mode, toggle } = useThemeMode()
  const dark = mode === 'dark'

  const [username,     setUsername]     = useState('')
  const [password,     setPassword]     = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [loading,      setLoading]      = useState(false)
  const [error,        setError]        = useState('')

  const handleLogin = async () => {
    if (!username || !password) { setError('Veuillez remplir tous les champs'); return }
    setLoading(true); setError('')
    try {
      const { data } = await authApi.login(username, password)
      login(data.access_token, data.role, data.username)
      navigate('/dashboard')
    } catch {
      setError('Identifiants incorrects. Essayez admin / admin')
    } finally {
      setLoading(false)
    }
  }

  const primary     = dark ? '#00aaff' : '#0070d4'
  const textPri     = dark ? '#e2ecf8' : '#1a2540'
  const textSec     = dark ? '#8aaccc' : '#5a7090'
  const border      = dark ? 'rgba(0,170,255,0.2)' : 'rgba(0,112,212,0.15)'
  const fieldBorder = dark ? 'rgba(0,170,255,0.2)' : 'rgba(0,112,212,0.2)'

  const fieldSx = {
    '& .MuiOutlinedInput-root': {
      color: textPri,
      '& fieldset': { borderColor: fieldBorder },
      '&:hover fieldset': { borderColor: primary },
      '&.Mui-focused fieldset': { borderColor: primary },
    },
    '& .MuiInputLabel-root': { color: textSec },
    '& .MuiInputLabel-root.Mui-focused': { color: primary },
  }

  return (
    <Box sx={{
      minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: dark
        ? 'radial-gradient(ellipse 60% 60% at 50% 50%, rgba(0,80,180,0.18) 0%, transparent 70%), #060d1e'
        : '#f0f4f8',
      overflow: 'hidden', position: 'relative',
    }}>
      {dark && (
        <Box sx={{
          position: 'absolute', inset: 0, pointerEvents: 'none',
          backgroundImage: 'linear-gradient(rgba(0,170,255,0.025) 1px, transparent 1px), linear-gradient(90deg, rgba(0,170,255,0.025) 1px, transparent 1px)',
          backgroundSize: '50px 50px',
        }} />
      )}

      {/* Theme toggle */}
      <Box
        onClick={toggle}
        sx={{
          position: 'fixed', top: 20, right: 20,
          px: 1.4, py: 0.6, borderRadius: '20px', cursor: 'pointer', userSelect: 'none',
          border: `1px solid ${border}`, bgcolor: dark ? 'rgba(0,170,255,0.06)' : '#fff',
          boxShadow: dark ? 'none' : '0 1px 4px rgba(0,0,0,0.08)',
          '&:hover': { borderColor: primary },
          display: 'flex', alignItems: 'center',
        }}
      >
        <Typography sx={{ fontSize: '0.72rem', fontWeight: 600, color: primary, fontFamily: '"JetBrains Mono", monospace', whiteSpace: 'nowrap' }}>
          {dark ? '☀ Mode clair' : '◑ Mode sombre'}
        </Typography>
      </Box>

      <motion.div
        initial={{ opacity: 0, y: 24, scale: 0.97 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ duration: 0.45, ease: 'easeOut' }}
      >
        <Box sx={{
          width: 420,
          background: dark ? 'rgba(10,22,48,0.92)' : '#ffffff',
          backdropFilter: dark ? 'blur(24px)' : 'none',
          border: `1px solid ${border}`,
          borderRadius: '20px',
          p: 5,
          boxShadow: dark ? '0 0 60px rgba(0,100,200,0.18)' : '0 8px 40px rgba(0,0,0,0.1)',
          position: 'relative', overflow: 'hidden',
          '&::before': {
            content: '""', position: 'absolute', top: 0, left: 0, right: 0, height: '2px',
            background: `linear-gradient(90deg, transparent, ${primary}, transparent)`,
          },
        }}>
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Box sx={{
              width: 56, height: 56, borderRadius: '14px', mx: 'auto', mb: 2,
              background: dark
                ? 'linear-gradient(135deg, rgba(0,100,200,0.28), rgba(0,255,200,0.18))'
                : 'linear-gradient(135deg, rgba(0,112,212,0.1), rgba(0,185,156,0.08))',
              border: `1px solid ${border}`,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '24px', boxShadow: dark ? `0 0 20px ${primary}44` : 'none',
            }}>
              🌿
            </Box>
            <Typography variant="h5" fontWeight={700} sx={{ color: textPri, mb: 0.5, letterSpacing: '-0.02em' }}>
              Smart Monitor
            </Typography>
            <Typography variant="body2" sx={{ color: textSec }}>
              Plateforme de surveillance environnementale
            </Typography>
          </Box>

          {error && (
            <Alert severity="error" sx={{ mb: 2.5, bgcolor: 'rgba(232,51,74,0.08)', border: '1px solid rgba(232,51,74,0.22)', color: '#e8334a', fontSize: '0.82rem' }}>
              {error}
            </Alert>
          )}

          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
            <TextField
              fullWidth label="Nom d'utilisateur" value={username}
              onChange={(e) => setUsername(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
              sx={fieldSx}
            />
            <Box sx={{ position: 'relative' }}>
              <TextField
                fullWidth label="Mot de passe"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
                sx={fieldSx}
              />
              <Box
                onClick={() => setShowPassword((v) => !v)}
                sx={{
                  position: 'absolute', right: 12, top: '50%', transform: 'translateY(-50%)',
                  cursor: 'pointer', fontSize: '0.72rem', fontWeight: 600, color: textSec,
                  fontFamily: '"JetBrains Mono", monospace', userSelect: 'none',
                  '&:hover': { color: primary },
                  transition: 'color 0.15s',
                }}
              >
                {showPassword ? 'Cacher' : 'Voir'}
              </Box>
            </Box>
            <Button
              fullWidth variant="contained" size="large"
              onClick={handleLogin} disabled={loading}
              sx={{
                mt: 0.5, py: 1.5, fontSize: '0.95rem', borderRadius: '10px', fontWeight: 700,
                background: `linear-gradient(135deg, ${dark ? '#0055aa' : '#004da0'}, ${primary})`,
                boxShadow: `0 4px 16px ${primary}44`,
                letterSpacing: '0.02em',
                '&:hover': { boxShadow: `0 6px 24px ${primary}55` },
              }}
            >
              {loading ? <CircularProgress size={22} sx={{ color: '#fff' }} /> : 'Connexion'}
            </Button>
          </Box>

          <Box sx={{ mt: 3, p: 1.8, bgcolor: dark ? 'rgba(0,170,255,0.04)' : 'rgba(0,112,212,0.04)', border: `1px solid ${fieldBorder}`, borderRadius: '10px' }}>
            <Typography sx={{ fontSize: '0.62rem', color: textSec, fontFamily: '"JetBrains Mono", monospace', mb: 0.5, textTransform: 'uppercase', letterSpacing: '0.06em' }}>
              Comptes de démonstration
            </Typography>
            <Typography sx={{ fontSize: '0.7rem', color: primary, fontFamily: '"JetBrains Mono", monospace', display: 'block' }}>
              admin / admin — accès complet
            </Typography>
            <Typography sx={{ fontSize: '0.7rem', color: dark ? '#00e87a' : '#10b981', fontFamily: '"JetBrains Mono", monospace', display: 'block' }}>
              viewer / admin — consultation
            </Typography>
          </Box>
        </Box>
      </motion.div>
    </Box>
  )
}

import { useState, useEffect, useRef, useCallback } from 'react'
import { internalApi, externalApi, WS_URL } from '../services/api'
import type { InternalData, ExternalData } from '../types'

export function useLatestSensorData(refreshInterval = 30000) {
  const [internal, setInternal] = useState<InternalData | null>(null)
  const [external, setExternal] = useState<ExternalData | null>(null)
  const [loading, setLoading] = useState(true)
  const [lastUpdate, setLastUpdate] = useState<Date | null>(null)
  const wsRef = useRef<WebSocket | null>(null)

  const fetchData = useCallback(async () => {
    try {
      const [inRes, exRes] = await Promise.all([
        internalApi.latest(),
        externalApi.latest(),
      ])
      setInternal(inRes.data)
      setExternal(exRes.data)
      setLastUpdate(new Date())
    } catch (e) {
      console.error('Fetch sensor data error:', e)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchData()
    const interval = setInterval(fetchData, refreshInterval)
    return () => clearInterval(interval)
  }, [fetchData, refreshInterval])

  useEffect(() => {
    let reconnectTimer: ReturnType<typeof setTimeout> | null = null

    const connect = () => {
      if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) return
      try {
        const ws = new WebSocket(WS_URL)
        wsRef.current = ws

        ws.onopen = () => {
          if (reconnectTimer) { clearTimeout(reconnectTimer); reconnectTimer = null }
        }

        ws.onmessage = (evt) => {
          try {
            const msg = JSON.parse(evt.data)
            if (msg.type === 'internal_update' && msg.data) {
              setInternal((prev) => {
                const base = prev ?? { id: 0, timestamp: msg.timestamp }
                return { ...base, ...msg.data, timestamp: msg.timestamp } as InternalData
              })
              setLastUpdate(new Date())
            } else if (msg.type === 'external_update' && msg.data) {
              setExternal((prev) => {
                const base = prev ?? { id: 0, timestamp: msg.timestamp }
                return { ...base, ...msg.data, timestamp: msg.timestamp } as ExternalData
              })
            }
          } catch {}
        }

        ws.onerror = () => {}
        ws.onclose = () => {
          reconnectTimer = setTimeout(connect, 5000)
        }
      } catch {
        reconnectTimer = setTimeout(connect, 5000)
      }
    }

    connect()

    return () => {
      if (reconnectTimer) clearTimeout(reconnectTimer)
      wsRef.current?.close()
      wsRef.current = null
    }
  }, [])

  return { internal, external, loading, lastUpdate, refetch: fetchData }
}

import ReactECharts from 'echarts-for-react'
import type { InternalData } from '../../types'
import { useThemeMode } from '../../context/ThemeContext'

interface LiveChartProps {
  data: InternalData[]
  metric: keyof InternalData
  label: string
  color: string
  unit: string
  optLow?: number
  optHigh?: number
}

export default function LiveChart({ data, metric, color, unit, optLow, optHigh }: LiveChartProps) {
  const { mode } = useThemeMode()
  const dark = mode === 'dark'

  const axisColor   = dark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.08)'
  const labelColor  = dark ? '#6a8fb0' : '#7a90a8'
  const gridColor   = dark ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.04)'
  const tooltipBg   = dark ? '#0d1c38' : '#ffffff'
  const tooltipText = dark ? '#e2ecf8' : '#1a2540'

  const timestamps = data.map((d) =>
    new Date(d.timestamp).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })
  )
  const values = data.map((d) => {
    const v = d[metric]
    return typeof v === 'number' ? parseFloat(v.toFixed(2)) : null
  })

  const allVals = values.filter((v) => v !== null) as number[]
  const minV = allVals.length ? Math.min(...allVals) : 0
  const maxV = allVals.length ? Math.max(...allVals) : 100
  const pad  = (maxV - minV) * 0.18 || 1

  const yMin = Math.floor(minV - pad)
  const yMax = Math.ceil(maxV + pad)

  const option = {
    backgroundColor: 'transparent',
    animation: true,
    animationDuration: 600,
    animationEasing: 'cubicOut',
    grid: { top: 12, right: 10, bottom: 32, left: 48 },
    tooltip: {
      trigger: 'axis',
      backgroundColor: tooltipBg,
      borderColor: `${color}44`,
      borderWidth: 1,
      padding: [9, 14],
      extraCssText: `box-shadow: 0 4px 20px rgba(0,0,0,${dark ? '0.5' : '0.12'});`,
      textStyle: { color: tooltipText, fontFamily: '"JetBrains Mono", monospace', fontSize: 11 },
      formatter: (params: any) => {
        const p = params[0]
        if (p.value === null || p.value === undefined) return ''
        return `<span style="color:${color};font-weight:700;font-size:14px">${p.value} <span style="font-size:11px;opacity:0.7">${unit}</span></span><br/><span style="opacity:0.45;font-size:10px">${p.axisValue}</span>`
      },
    },
    xAxis: {
      type: 'category',
      data: timestamps,
      boundaryGap: false,
      axisLine:  { lineStyle: { color: axisColor } },
      axisTick:  { show: false },
      axisLabel: {
        color: labelColor, fontSize: 9,
        fontFamily: '"JetBrains Mono", monospace',
        interval: Math.max(0, Math.floor(timestamps.length / 5) - 1),
      },
      splitLine: { show: false },
    },
    yAxis: {
      type: 'value',
      min: yMin, max: yMax,
      axisLine: { show: false },
      axisTick: { show: false },
      axisLabel: { color: labelColor, fontSize: 9, fontFamily: '"JetBrains Mono", monospace' },
      splitLine: { lineStyle: { color: gridColor, type: 'dashed', dashOffset: 4 } },
    },
    series: [{
      type: 'line',
      data: values,
      smooth: 0.4,
      symbol: 'circle',
      symbolSize: (v: number | null) => (v !== null && timestamps.length <= 40) ? 5 : 0,
      showSymbol: timestamps.length <= 40,
      lineStyle: { color, width: 2.5, shadowColor: `${color}55`, shadowBlur: 8 },
      itemStyle: { color, borderColor: dark ? '#0d1c38' : '#fff', borderWidth: 2 },
      areaStyle: {
        color: {
          type: 'linear', x: 0, y: 0, x2: 0, y2: 1,
          colorStops: [
            { offset: 0, color: `${color}4a` },
            { offset: 0.6, color: `${color}18` },
            { offset: 1, color: `${color}00` },
          ],
        },
      },
      markArea: (optLow !== undefined && optHigh !== undefined) ? {
        silent: true,
        itemStyle: { color: `${color}0d`, borderWidth: 0 },
        data: [[
          { yAxis: optLow, label: { show: false } },
          { yAxis: optHigh },
        ]],
      } : undefined,
      markLine: allVals.length ? {
        silent: true,
        symbol: ['none', 'none'],
        lineStyle: { color: `${color}55`, type: 'dashed', width: 1 },
        label: { show: false },
        data: [{ type: 'average' }],
      } : undefined,
    }],
  }

  return <ReactECharts option={option} style={{ height: 180 }} opts={{ renderer: 'canvas' }} />
}

import { createContext, useContext, useState, useMemo } from 'react'
import { createTheme, Theme } from '@mui/material/styles'

type ColorMode = 'dark' | 'light'

interface ThemeModeCtx {
  mode: ColorMode
  toggle: () => void
  theme: Theme
}

const Ctx = createContext<ThemeModeCtx>({} as ThemeModeCtx)

function buildTheme(mode: ColorMode): Theme {
  const dark = mode === 'dark'
  return createTheme({
    palette: {
      mode,
      primary:    { main: dark ? '#00aaff' : '#0070d4', light: dark ? '#33bbff' : '#3394e8', dark: dark ? '#0077cc' : '#0050a0' },
      secondary:  { main: dark ? '#00ffcc' : '#00b89c' },
      error:      { main: '#e8334a' },
      warning:    { main: '#f59e0b' },
      success:    { main: dark ? '#00e87a' : '#10b981' },
      background: {
        default: dark ? '#060d1e' : '#f2f5fa',
        paper:   dark ? 'rgba(10,22,48,0.92)' : '#ffffff',
      },
      text: {
        primary:   dark ? '#e2ecf8' : '#1a2540',
        secondary: dark ? '#8aaccc' : '#5a7090',
      },
      divider: dark ? 'rgba(0,170,255,0.1)' : 'rgba(0,100,180,0.1)',
    },
    typography: {
      fontFamily: '"Inter", system-ui, -apple-system, sans-serif',
      h5: { fontWeight: 700, letterSpacing: '-0.02em' },
      h6: { fontWeight: 600, letterSpacing: '-0.01em' },
      body1: { fontSize: '0.9rem' },
      body2: { fontSize: '0.8rem' },
      caption: { fontFamily: '"JetBrains Mono", monospace', fontSize: '0.72rem' },
    },
    shape: { borderRadius: 12 },
    components: {
      MuiCssBaseline: {
        styleOverrides: {
          '@import': "url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600;700&display=swap')",
          body: {
            background: dark ? '#060d1e' : '#f2f5fa',
            scrollbarColor: dark ? 'rgba(0,170,255,0.25) transparent' : 'rgba(0,100,180,0.18) transparent',
            '&::-webkit-scrollbar': { width: 5 },
            '&::-webkit-scrollbar-track': { background: 'transparent' },
            '&::-webkit-scrollbar-thumb': {
              borderRadius: 3,
              background: dark ? 'rgba(0,170,255,0.22)' : 'rgba(0,100,180,0.18)',
            },
          },
        },
      },
      MuiPaper: {
        styleOverrides: {
          root: {
            backgroundImage: 'none',
            background: dark ? 'rgba(10,22,48,0.88)' : '#ffffff',
            backdropFilter: dark ? 'blur(16px)' : 'none',
            border: `1px solid ${dark ? 'rgba(0,170,255,0.09)' : 'rgba(0,80,160,0.09)'}`,
            boxShadow: dark ? 'none' : '0 1px 6px rgba(0,0,0,0.07)',
          },
        },
      },
      MuiButton: {
        styleOverrides: {
          root: { textTransform: 'none', fontWeight: 600, letterSpacing: '0.01em' },
        },
      },
      MuiChip: {
        styleOverrides: {
          root: { fontFamily: '"JetBrains Mono", monospace', fontWeight: 500 },
        },
      },
      MuiTableCell: {
        styleOverrides: {
          root: {
            borderBottom: `1px solid ${dark ? 'rgba(0,170,255,0.06)' : 'rgba(0,80,160,0.07)'}`,
          },
        },
      },
    },
  })
}

export function ThemeModeProvider({ children }: { children: React.ReactNode }) {
  const [mode, setMode] = useState<ColorMode>(
    () => (localStorage.getItem('serre-color-mode') as ColorMode) ?? 'dark'
  )

  const toggle = () =>
    setMode((m) => {
      const next = m === 'dark' ? 'light' : 'dark'
      localStorage.setItem('serre-color-mode', next)
      return next
    })

  const theme = useMemo(() => buildTheme(mode), [mode])

  return <Ctx.Provider value={{ mode, toggle, theme }}>{children}</Ctx.Provider>
}

export const useThemeMode = () => useContext(Ctx)
